class MyApp extends StatelessWidget {
  const MyApp({
    Key? key,
  }) : super(key: key);

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Sample Input Client',
      theme: ThemeData(
        primarySwatch: Colors.blue,
      ),
      home: const HomeScreen(),
    );
  }
}

class HomeScreen extends StatelessWidget {
  const HomeScreen({
    Key? key,
  }) : super(key: key);

  @override
  Widget build(BuildContext context) {
    return const Scaffold(
      body: SafeArea(
        child: Center(
          child: Padding(
            padding: EdgeInsets.symmetric(horizontal: 16.0),
            child: SampleInputField(),
          ),
        ),
      ),
    );
  }
}

class SampleInputField extends StatefulWidget {
  const SampleInputField({
    Key? key,
  }) : super(key: key);

  @override
  State<SampleInputField> createState() => _SampleInputFieldState();
}

class _SampleInputFieldState extends State<SampleInputField>
    implements TextInputClient {
  late final TextEditingController _textEditingController;
  TextInputConnection? _textInputConnection;

  @override
  void initState() {
    super.initState();

    _textEditingController = TextEditingController();
  }

  @override
  void dispose() {
    _textEditingController.dispose();
    _textInputConnection?.close();

    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Column(
      mainAxisAlignment: MainAxisAlignment.center,
      children: <Widget>[
        GestureDetector(
          onTap: () {
            _handleInputConnection();
          },
          child: Container(
            height: 100.0,
            color: Colors.blue,
            child: const Center(
              child: Text('TAP ME'),
            ),
          ),
        ),
        ValueListenableBuilder<TextEditingValue>(
          valueListenable: _textEditingController,
          builder: (context, value, _) {
            return Text(value.text);
          },
        ),
      ],
    );
  }

  void _handleInputConnection() {
    final connectionIsNotAttached = !(_textInputConnection?.attached ?? false);
    if (connectionIsNotAttached) {
      const config = TextInputConfiguration(
        // this is default value and everything works fine
        inputType: TextInputType.text,
        // with this 3 types input doesn't work properly
        // inputType: TextInputType.phone,
        // inputType: TextInputType.number,
        // inputType: TextInputType.numberWithOptions(),
      );
      _textInputConnection = TextInput.attach(this, config);
    }

    _textInputConnection!
      ..setEditingState(_textEditingController.value)
      ..show();
  }

  @override
  void connectionClosed() {}

  @override
  AutofillScope? get currentAutofillScope => null;

  @override
  TextEditingValue? get currentTextEditingValue => _textEditingController.value;

  @override
  void performAction(TextInputAction action) {
    switch (action) {
      case TextInputAction.done:
        _textInputConnection?.close();
        break;
      case TextInputAction.none:
      case TextInputAction.unspecified:
      case TextInputAction.go:
      case TextInputAction.search:
      case TextInputAction.send:
      case TextInputAction.next:
      case TextInputAction.previous:
      case TextInputAction.continueAction:
      case TextInputAction.join:
      case TextInputAction.route:
      case TextInputAction.emergencyCall:
      case TextInputAction.newline:
        break;
    }
  }

  @override
  void performPrivateCommand(String action, Map<String, dynamic> data) {}

  @override
  void showAutocorrectionPromptRect(int start, int end) {}

  @override
  void updateEditingValue(TextEditingValue value) {
    print('update value ${value.text}');
    _textEditingController.value = value;
  }

  @override
  void updateFloatingCursor(RawFloatingCursorPoint point) {}
}
